function countPrimes(n) {
  // Build an array `isPrime` of length n, all true.
  // Mark 0 and 1 as not prime.
  // For each i from 2 up to √n:
  //   if isPrime[i], mark every multiple of i (starting from i²) as not prime.
  // Count the true entries below n.
}

solution:
// O(n log log n) time, O(n) space.
// Each composite number gets marked once for each of its prime factors.
// The sum 1/2 + 1/3 + 1/5 + 1/7 + ... over primes ≤ n is ~log log n.
function countPrimes(n) {
  if (n < 2) return 0;
  const isPrime = new Array(n).fill(true);
  isPrime[0] = isPrime[1] = false;

  for (let i = 2; i * i < n; i++) {
    if (isPrime[i]) {
      // Start at i² — smaller multiples already marked by smaller primes.
      for (let j = i * i; j < n; j += i) {
        isPrime[j] = false;
      }
    }
  }
  let count = 0;
  for (let i = 2; i < n; i++) if (isPrime[i]) count++;
  return count;
}
